create extension if not exists postgis;
create table profiles(id uuid primary key references auth.users(id) on delete cascade,full_name text not null,avatar_url text,city text not null,neighborhood text,created_at timestamptz default now(),updated_at timestamptz default now(),rating_avg numeric default 0,rating_count int default 0,completed_count int default 0);
create table listings(id uuid primary key default gen_random_uuid(),owner_id uuid references profiles(id) on delete cascade not null,type text not null check(type in('OFFER','REQUEST','SWAP','LEND','HELP','PUBLIC_TREE')),category text not null check(category in('produce','herbs','eggs','seeds','seedlings','cuttings','compost','tools','help','public_trees','other')),title text not null,description text not null,quantity text,exchange_preference text,price numeric,status text default 'available' check(status in('available','reserved','closed')),city text not null,neighborhood text,location geography(Point,4326) not null,approximate_location geography(Point,4326),pickup_notes text,availability_notes text,expires_at timestamptz,created_at timestamptz default now(),updated_at timestamptz default now(),completed_at timestamptz);
create table listing_images(id uuid primary key default gen_random_uuid(),listing_id uuid references listings(id) on delete cascade,url text not null,sort_order int default 0,created_at timestamptz default now());
create table conversations(id uuid primary key default gen_random_uuid(),listing_id uuid references listings(id) on delete cascade not null,participant_a uuid references profiles(id) not null,participant_b uuid references profiles(id) not null,last_message text,last_message_at timestamptz,created_at timestamptz default now(),unique(listing_id,participant_a,participant_b));
create table messages(id uuid primary key default gen_random_uuid(),conversation_id uuid references conversations(id) on delete cascade not null,sender_id uuid references profiles(id) not null,body text not null,read_at timestamptz,created_at timestamptz default now());
create table reviews(id uuid primary key default gen_random_uuid(),listing_id uuid references listings(id) on delete cascade not null,reviewer_id uuid references profiles(id) not null,reviewee_id uuid references profiles(id) not null,rating int check(rating between 1 and 5),review_type text check(review_type in('share','exchange','lend','help')),text text,created_at timestamptz default now());
create table reports(id uuid primary key default gen_random_uuid(),reporter_id uuid references profiles(id) not null,listing_id uuid references listings(id),reported_user_id uuid references profiles(id),message_id uuid references messages(id),reason text not null check(reason in('spam','unsafe','private_property','inaccurate_location','inappropriate','other')),details text,created_at timestamptz default now(),status text default 'open');
create table saved_locations(id uuid primary key default gen_random_uuid(),user_id uuid references profiles(id) on delete cascade,label text,city text,neighborhood text,location geography(Point,4326),created_at timestamptz default now());
create table saved_listings(user_id uuid references profiles(id) on delete cascade,listing_id uuid references listings(id) on delete cascade,created_at timestamptz default now(),primary key(user_id,listing_id));
create table notification_preferences(user_id uuid primary key references profiles(id) on delete cascade,new_messages boolean default true,nearby_listings boolean default false,review_requests boolean default true,updated_at timestamptz default now());
create index listings_location_gix on listings using gist(location);create index listings_city_idx on listings(city);create index listings_category_idx on listings(category);create index listings_type_idx on listings(type);create index listings_status_idx on listings(status);create index listings_created_at_idx on listings(created_at desc);
create or replace function nearby_listings(user_lat double precision,user_lng double precision,radius_km double precision,type_filter text default null,category_filter text default null,search_query text default null) returns table(id uuid,owner_id uuid,type text,category text,title text,description text,quantity text,exchange_preference text,price numeric,status text,city text,neighborhood text,lat double precision,lng double precision,created_at timestamptz,completed_at timestamptz,distance_km double precision) language sql stable as $$ select l.id,l.owner_id,l.type,l.category,l.title,l.description,l.quantity,l.exchange_preference,l.price,l.status,l.city,l.neighborhood,st_y(l.location::geometry),st_x(l.location::geometry),l.created_at,l.completed_at,st_distance(l.location,st_setsrid(st_makepoint(user_lng,user_lat),4326)::geography)/1000 from listings l where l.status='available' and st_dwithin(l.location,st_setsrid(st_makepoint(user_lng,user_lat),4326)::geography,radius_km*1000) and (type_filter is null or l.type=type_filter) and (category_filter is null or l.category=category_filter) and (search_query is null or l.title ilike '%'||search_query||'%' or l.description ilike '%'||search_query||'%' or l.category ilike '%'||search_query||'%') order by distance_km asc,l.created_at desc $$;
alter table profiles enable row level security;alter table listings enable row level security;alter table listing_images enable row level security;alter table conversations enable row level security;alter table messages enable row level security;alter table reviews enable row level security;alter table reports enable row level security;alter table saved_locations enable row level security;alter table saved_listings enable row level security;alter table notification_preferences enable row level security;
create policy "profiles readable" on profiles for select to authenticated using(true);create policy "own profile write" on profiles for all to authenticated using(auth.uid()=id) with check(auth.uid()=id);
create policy "available listings readable" on listings for select to authenticated using(status='available' or owner_id=auth.uid());create policy "owner inserts listings" on listings for insert to authenticated with check(owner_id=auth.uid());create policy "owner updates listings" on listings for update to authenticated using(owner_id=auth.uid()) with check(owner_id=auth.uid());create policy "owner deletes listings" on listings for delete to authenticated using(owner_id=auth.uid());
create policy "listing images readable" on listing_images for select to authenticated using(true);create policy "conversation participants" on conversations for select to authenticated using(auth.uid() in(participant_a,participant_b));create policy "conversation participants insert" on conversations for insert to authenticated with check(auth.uid() in(participant_a,participant_b));create policy "message participants read" on messages for select to authenticated using(exists(select 1 from conversations c where c.id=conversation_id and auth.uid() in(c.participant_a,c.participant_b)));create policy "send own messages" on messages for insert to authenticated with check(sender_id=auth.uid() and exists(select 1 from conversations c where c.id=conversation_id and auth.uid() in(c.participant_a,c.participant_b)));create policy "reviews readable" on reviews for select to authenticated using(true);create policy "reviewer creates" on reviews for insert to authenticated with check(reviewer_id=auth.uid());create policy "reports create" on reports for insert to authenticated with check(reporter_id=auth.uid());
